type GetReturn&lt;T&gt; =
  T extends (...args: any[])
    =&gt; any
    ? ReturnType&lt;T&gt;
    : never;

slides.code:
// Extract array element type
type Elem&lt;T&gt; =
  T extends (infer E)[] ? E : never;

// Unwrap a Promise
type Unwrap&lt;T&gt; =
  T extends Promise&lt;infer V&gt;
    ? V : T;

// Extract prop type from object
type PropType&lt;T, K extends keyof T&gt; =
  T extends { [P in K]: infer V }
    ? V : never;

// First element of a tuple
type First&lt;T&gt; =
  T extends [infer F, ...any[]] ? F : never;
